logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_BUCKET = os.environ.get("OUTPUT_BUCKET", "")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")


def process_image(bucket_name, object_key):
    """
    Placeholder image processing function.
    For MVP purposes, this reads the object and returns simple metadata.
    Extend this later with actual image transformation logic.
    """
    response = s3.get_object(Bucket=bucket_name, Key=object_key)
    content_type = response.get("ContentType", "application/octet-stream")
    body = response["Body"].read()

    result = {
        "source_bucket": bucket_name,
        "source_key": object_key,
        "content_type": content_type,
        "size_bytes": len(body),
        "status": "processed"
    }
    return result


def write_result_to_s3(output_bucket, source_key, result_data):
    result_key = f"results/{source_key}.json"
    s3.put_object(
        Bucket=output_bucket,
        Key=result_key,
        Body=json.dumps(result_data, indent=2).encode("utf-8"),
        ContentType="application/json"
    )
    return result_key


def send_notification(topic_arn, message, subject="Image Processing Complete"):
    if not topic_arn:
        logger.info("SNS_TOPIC_ARN not set; skipping notification.")
        return None

    response = sns.publish(
        TopicArn=topic_arn,
        Subject=subject[:100],
        Message=message
    )
    return response.get("MessageId")


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    records = event.get("Records", [])
    if not records:
        logger.warning("No S3 records found in event.")
        return {
            "statusCode": 400,
            "body": json.dumps({"message": "No S3 records found"})
        }

    processed_items = []

    for record in records:
        try:
            s3_info = record.get("s3", {})
            bucket_name = s3_info.get("bucket", {}).get("name")
            object_key = unquote_plus(s3_info.get("object", {}).get("key", ""))

            if not bucket_name or not object_key:
                logger.warning("Missing bucket or key in record: %s", record)
                continue

            logger.info("Processing s3://%s/%s", bucket_name, object_key)

            result = process_image(bucket_name, object_key)

            target_bucket = OUTPUT_BUCKET or bucket_name
            result_key = write_result_to_s3(target_bucket, object_key, result)

            notification_message = (
                f"Processed image from s3://{bucket_name}/{object_key}\n"
                f"Result written to s3://{target_bucket}/{result_key}\n"
                f"Result: {json.dumps(result)}"
            )
            message_id = send_notification(SNS_TOPIC_ARN, notification_message)

            processed_items.append({
                "source_bucket": bucket_name,
                "source_key": object_key,
                "output_bucket": target_bucket,
                "result_key": result_key,
                "sns_message_id": message_id
            })

        except ClientError as e:
            logger.exception("AWS client error while processing record.")
            processed_items.append({
                "error": str(e)
            })
        except Exception as e:
            logger.exception("Unexpected error while processing record.")
            processed_items.append({
                "error": str(e)
            })

    response_body = {
        "message": "Processing complete",
        "processed_count": len(processed_items),
        "items": processed_items
    }

    logger.info("Processing complete: %s", json.dumps(response_body))
    return {
        "statusCode": 200,
        "body": json.dumps(response_body)
    }